def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    n = len(bins)
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if item > capacity:
            continue
        ratio = item / capacity
        base_score = 0.0
        if ratio == 1:
            base_score = 0.0
        elif ratio > 0.9:
            base_score = (1 - ratio) ** 4 + 0.15
        elif ratio > 0.7:
            base_score = np.exp(-15 * ratio) + 0.12
        elif ratio > 0.4:
            for k in range(1, 10):
                base_score += ((-1) ** k) * (ratio ** (k + 2)) / (k + 0.5)
            base_score = abs(base_score) + 0.07
        else:
            poly_sum = 0
            for p in range(1, 4):
                poly_sum += (ratio ** p) / (p + 1)
            base_score = np.sqrt(poly_sum) + 0.1
        neighbor_influence = 0.0
        for offset in range(1, 7):
            neighbors = []
            if i - offset >= 0:
                neighbors.append(bins[i - offset])
            if i + offset < n:
                neighbors.append(bins[i + offset])
            for neighbor_capacity in neighbors:
                if neighbor_capacity <= 0:
                    continue
                diff = abs(capacity - neighbor_capacity)
                max_cap = max(capacity, neighbor_capacity)
                diff_ratio = diff / max_cap
                weight = 1 / (offset ** 2)
                sign = 1 if capacity > neighbor_capacity else -1
                neighbor_influence += sign * diff_ratio * weight * 0.05
        capacity_factor = np.log1p(capacity)
        if capacity_factor == 0:
            capacity_factor = 1
        penalty = 0.0
        remaining = capacity - item
        if remaining > 1:
            is_prime = True
            for num in range(2, int(np.sqrt(remaining)) + 1):
                if remaining % num == 0:
                    is_prime = False
                    break
            if is_prime:
                penalty = 0.2
        priority = base_score + neighbor_influence / capacity_factor + penalty
        if priority < 0:
            priority = 0
        if capacity < item * 1.1 and capacity >= item:
            priority *= 0.6
        if i % 2 == 0:
            priority *= 0.95
        else:
            priority *= 1.05
        noise = (np.sin(i * 7.13) + 1) * 0.01
        priority += noise
        priorities[i] = priority
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10
    return priorities
